  const amp = 1 / Math.sqrt(8);
  const indices = [0, 2, 4, 6, 9, 11, 13, 15];
  indices.forEach(idx => {
    state[idx] = { re: amp, im: 0 };
  });
  return state;
};

export const generateQecTargetState = (): StateVector => {
